# ── File existence ────────────────────────────────────────────────────────────

@pytest.mark.parametrize("rel_path", V242_FILES)
def test_v242_file_exists(rel_path):
    assert (ROOT / rel_path).exists(), f"v2.4.2 file missing: {rel_path}"


def test_omnigraph_script_executable():
    path = ROOT / V242_OMNIGRAPH_SCRIPT
    assert path.exists()
    assert os.access(path, os.X_OK), f"Script not executable: {V242_OMNIGRAPH_SCRIPT}"


# ── Attribution audit ─────────────────────────────────────────────────────────

@pytest.mark.parametrize("rel_path", V242_FILES)
def test_no_external_attribution(rel_path):
    path = ROOT / rel_path
    if not path.exists():
        pytest.skip(f"File not found: {rel_path}")
    content = path.read_text()
    for phrase in ATTRIBUTION_STRINGS:
        assert phrase not in content, (
            f"External attribution found in {rel_path}: {phrase!r}"
        )


