def test_omnigraph_script_has_no_isaac_sim_hard_dependency():
    """Script must exit 0 when omni.graph.core is not available (CI safety)."""
    result = subprocess.run(
        [sys.executable, str(ROOT / V242_OMNIGRAPH_SCRIPT)],
        capture_output=True,
        text=True,
        cwd=str(ROOT),
    )
    assert result.returncode == 0, (
        f"OmniGraph script must exit 0 without Isaac Sim:\n"
        f"stdout: {result.stdout}\nstderr: {result.stderr}"
    )
    out = result.stdout
    assert "[OK]" in out or "[INFO]" in out, (
        "Script must print [OK] or [INFO] when run without Isaac Sim"
    )


def test_omnigraph_script_prints_graph_plan():
    result = subprocess.run(
        [sys.executable, str(ROOT / V242_OMNIGRAPH_SCRIPT)],
        capture_output=True,
        text=True,
        cwd=str(ROOT),
    )
    out = result.stdout
    assert "/World/ROS2ActionGraph" in out, (
        "Script must print the graph path"
    )
    assert "/camera/image_raw" in out
    assert "/odom" in out
    assert "/tf" in out
    assert "/scan" in out
    assert "/cmd_vel" in out


def test_omnigraph_script_prints_prim_paths():
    result = subprocess.run(
        [sys.executable, str(ROOT / V242_OMNIGRAPH_SCRIPT)],
        capture_output=True,
        text=True,
        cwd=str(ROOT),
    )
    out = result.stdout
    assert "/World/YahboomM3Pro/camera_link/sensor" in out, (
        "Script must print camera prim path in graph plan"
    )
    assert "/World/YahboomM3Pro/base_link" in out
    assert "/World/YahboomM3Pro/lidar_link" in out


